import React from 'react';
import './App.css'; 
// Silinmeyen App.css dosyamızı buraya dahil ediyoruz.

function App() {
  return (
    <div className="App">
      <div className="dashboard-container">
        {/* 1. Başlık Alanı */}
        <header className="header">
          <h1>📊 InsightFlow KDS: E-Ticaret Performans Panosu</h1>
          {/* Zaman Filtresi Buraya Gelecek */}
        </header>

        {/* 2. KPI Kartları Alanı */}
        <div className="kpi-cards" style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '30px' }}>
          <div style={cardStyle}>Toplam Ciro</div>
          <div style={cardStyle}>Dönüşüm Oranı</div>
          <div style={cardStyle}>Yeni Müşteriler</div>
          <div style={cardStyle}>Ortalama Sipariş Değeri</div>
        </div>

        {/* 3. Grafik Alanı */}
        <div className="charts-area" style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '20px' }}>
          <div style={{...chartStyle, height: '400px'}}>Gelir Trend Grafiği (Zaman Serisi)</div>
          <div style={{...chartStyle, height: '400px'}}>Ürün Kategori Dağılımı (Pasta Grafik)</div>
        </div>

        {/* 4. Detay Tablolar Alanı */}
        <div className="details-area" style={{ marginTop: '30px', padding: '20px', borderTop: '1px solid #ccc' }}>
          <h2>Bölgesel Satış Detayı ve Hedef Takibi</h2>
          {/* Buraya harita ve hedef takibi gelecek */}
        </div>

      </div>
    </div>
  );
}

// Basit Kart Stili Tanımlayalım
const cardStyle = {
  flex: 1,
  margin: '0 10px',
  padding: '20px',
  backgroundColor: '#ffffff',
  borderRadius: '8px',
  boxShadow: '0 4px 8px rgba(0, 0, 0, 0.1)',
  fontSize: '1.2em',
  fontWeight: 'bold'
};

const chartStyle = {
  backgroundColor: '#ffffff',
  padding: '20px',
  borderRadius: '8px',
  boxShadow: '0 4px 8px rgba(0, 0, 0, 0.1)'
};

export default App;
